module top_module(
input [47:0]mi,
input [7:0] eo,
output reg [22:0]mout,
output reg[7:0]eout,
input EN
);always @(EN,mi,eo)
if (EN == 1'b1) 
begin
	if (mi[47]==1)	begin
	eout <= eo +1'b1;
	mout <= mi[46:24];
					end    
	else begin
	 eout <= eo;
	 mout <= mi[45:23];
	 end
	 end
else begin
	eout <= 0;
	mout <= mi[22:0];
end
endmodule
